15	interface QuoteResult {
16	  premium: number;
17	}
18	
19	const PROCESSING_FEE = 5;
20	const FIRST_INSURANCE_RATE = 0.1;
21	
22	const BASE_PREMIUM: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	  potion: 40,
27	  rune: 25,
28	  moonstone: 25,
29	};
30	
31	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
32	const BLOCK_SIZE = 3;
33	const BLOCK_BASE_PREMIUM = 60;
34	
35	const itemsBaseForType = (type: string, count: number): number => {
36	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) return BLOCK_BASE_PREMIUM;
37	  return count * BASE_PREMIUM[type];
38	};
39	
40	const countByType = (items: Item[]): Map<string, number> =>
41	  items.reduce(
42	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
43	    new Map<string, number>(),
44	  );
45	
46	const policyBase = (items: Item[]): number =>
47	  Array.from(countByType(items)).reduce(
48	    (total, [type, count]) => total + itemsBaseForType(type, count),
49	    0,
50	  );
51	
52	const quoteStep = (step: QuoteStep): QuoteResult => {
53	  const base = policyBase(step.items);
54	  const firstInsurance = base * FIRST_INSURANCE_RATE;
55	  return { premium: Math.ceil(base + firstInsurance + PROCESSING_FEE) };
56	};
57	
58	export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
59	  const results = scenario.steps.map(quoteStep);
60	  return { results };
61	};
62

